#!/usr/bin/env node
// One-way repo -> Figma sync of design tokens to Figma local Variables.
//
// Source of truth: figma-tokens.json (generated by Style Dictionary from
// tokens/*.json — never hand-edited). Target: the `cs.*` variable collections
// in the Figma design file. The repo is authoritative; Figma is downstream.
//
// SAFETY MANDATE (this touches the shared Figma design source of truth):
//   * CREATE-OR-UPDATE ONLY. This tool NEVER deletes collections, modes, or
//     variables. Anything present in Figma but absent from the manifest is
//     reported as "extra (left untouched)" — never removed. `buildPostPayload`
//     structurally cannot emit a DELETE action, and `assertNoDeletes` re-checks
//     the payload before any network write.
//   * DRY-RUN IS THE DEFAULT. `--dry-run` (default) reads current Figma state
//     and prints the diff; it performs no writes. CI runs report-only.
//   * The real apply path (`--apply`) is DOUBLE-GATED: it prints the exact POST
//     payload and refuses to send unless FIGMA_SYNC_ALLOW_APPLY=1 is also set.
//     The first real apply should be reviewed by the operator.
//
// Requires a Figma PAT in FIGMA_ACCESS_TOKEN with (Enterprise) scopes:
//   file_variables:read  (dry-run / diff)   ·   file_variables:write (--apply)
//
// Effect styles (manifest.effectStyles) are NOT synced: the Figma REST API has
// no endpoint to create/update styles (plugin/UI only). The underlying color
// (cs.color/shadow) IS synced as a normal COLOR variable.
//
// Usage:
//   node scripts/figma-variables-sync.mjs [--dry-run] [--apply] [--json]
//        [--file-key <key>] [--manifest <path>] [--current <path>]
import { readFileSync, appendFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join, resolve } from "node:path";

export const DEFAULT_FILE_KEY = "twQmWC8dWT4tqeqIigNsRy";
const FIGMA_API = "https://api.figma.com";
const COLOR_EPSILON = 1e-4; // ~1/255 distinguishes a real 8-bit step from float noise
const FLOAT_EPSILON = 1e-6;

// ---------------------------------------------------------------------------
// Pure helpers (unit-tested in figma-variables-sync.test.mjs)
// ---------------------------------------------------------------------------

/** Convert `#rrggbb`/`#rgb` + alpha (0..1) to a Figma color `{r,g,b,a}` (0..1). */
export function hexToRgba(hex, alpha = 1) {
  const h = String(hex).trim().replace(/^#/, "");
  const full =
    h.length === 3
      ? h
          .split("")
          .map((c) => c + c)
          .join("")
      : h;
  if (!/^[0-9a-fA-F]{6}$/.test(full)) {
    throw new Error(`invalid hex color: ${hex}`);
  }
  return {
    r: parseInt(full.slice(0, 2), 16) / 255,
    g: parseInt(full.slice(2, 4), 16) / 255,
    b: parseInt(full.slice(4, 6), 16) / 255,
    a: typeof alpha === "number" ? alpha : 1,
  };
}

export function colorsEqual(a, b) {
  if (!a || !b) return false;
  return (
    Math.abs(a.r - b.r) <= COLOR_EPSILON &&
    Math.abs(a.g - b.g) <= COLOR_EPSILON &&
    Math.abs(a.b - b.b) <= COLOR_EPSILON &&
    Math.abs((a.a ?? 1) - (b.a ?? 1)) <= COLOR_EPSILON
  );
}

/** Compare two resolved values for a given Figma resolvedType. */
export function valuesEqual(type, a, b) {
  if (a === undefined || b === undefined) return false;
  switch (type) {
    case "COLOR":
      return colorsEqual(a, b);
    case "FLOAT":
      return typeof a === "number" && typeof b === "number"
        ? Math.abs(a - b) <= FLOAT_EPSILON
        : a === b;
    case "STRING":
    case "BOOLEAN":
    default:
      return a === b;
  }
}

/** Normalise a manifest variable's per-mode value into a Figma value. */
function manifestValueFor(type, raw) {
  if (type === "COLOR") {
    // raw = { hex, alpha }
    return hexToRgba(raw.hex, raw.alpha ?? 1);
  }
  // FLOAT -> number, STRING -> string (raw already primitive)
  return raw;
}

/**
 * Build the desired collection model from the token manifest.
 * Returns: [{ name, modes:[modeName], variables:[{ name, type, scopes,
 *            codeSyntax, description, valuesByMode:{ modeName: value } }] }]
 */
export function buildDesiredCollections(manifest) {
  const collections = Array.isArray(manifest.collections)
    ? manifest.collections
    : [];
  return collections.map((col) => ({
    name: col.name,
    modes: Array.isArray(col.modes) ? col.modes.slice() : [],
    variables: (col.variables || []).map((v) => {
      const valuesByMode = {};
      for (const [mode, raw] of Object.entries(v.values || {})) {
        valuesByMode[mode] = manifestValueFor(v.type, raw);
      }
      return {
        name: v.name,
        type: v.type,
        scopes: Array.isArray(v.scopes) ? v.scopes.slice() : [],
        codeSyntax: v.codeSyntax || {},
        description: v.description || "",
        valuesByMode,
      };
    }),
  }));
}

/** Index the GET /variables/local `meta` payload by human-readable names. */
export function indexCurrent(meta) {
  const collectionsByName = new Map();
  const variableCollections = (meta && meta.variableCollections) || {};
  const variables = (meta && meta.variables) || {};

  for (const col of Object.values(variableCollections)) {
    if (col.remote) continue; // only local collections are editable
    const modesByName = new Map();
    const modeNameById = new Map();
    for (const m of col.modes || []) {
      modesByName.set(m.name, m.modeId);
      modeNameById.set(m.modeId, m.name);
    }
    collectionsByName.set(col.name, {
      id: col.id,
      defaultModeId: col.defaultModeId,
      modesByName,
      modeNameById,
      variablesByName: new Map(),
    });
  }

  for (const v of Object.values(variables)) {
    if (v.remote) continue;
    const owner = Object.values(variableCollections).find(
      (c) => c.id === v.variableCollectionId && !c.remote,
    );
    if (!owner) continue;
    const entry = collectionsByName.get(owner.name);
    if (!entry) continue;
    entry.variablesByName.set(v.name, {
      id: v.id,
      resolvedType: v.resolvedType,
      valuesByMode: v.valuesByMode || {},
      scopes: v.scopes || [],
      codeSyntax: v.codeSyntax || {},
      description: v.description || "",
    });
  }
  return { collectionsByName };
}

function scopesEqual(a, b) {
  const sa = [...(a || [])].sort();
  const sb = [...(b || [])].sort();
  return sa.length === sb.length && sa.every((x, i) => x === sb[i]);
}

function codeSyntaxEqual(a, b) {
  const ka = Object.keys(a || {}).sort();
  const kb = Object.keys(b || {}).sort();
  if (ka.length !== kb.length || !ka.every((k, i) => k === kb[i])) return false;
  return ka.every((k) => a[k] === b[k]);
}

/**
 * Compute a create-or-update-only plan. Never proposes deletions. Returns a
 * structured plan the reporter and payload-builder both consume.
 */
export function diff(desiredCollections, currentIndex) {
  const plan = {
    createCollections: [], // { name, modes, variables:[desiredVar] }
    createModes: [], // { collectionName, modeName }
    createVariables: [], // { collectionName, variable }
    updateVariables: [], // { collectionName, name, id, changes:{scopes?,codeSyntax?,description?} }
    setValues: [], // { collectionName, variableName, mode, value, type, existing:boolean }
    extras: { collections: [], variables: [] }, // present in Figma, absent in manifest (untouched)
    warnings: [], // e.g. type mismatch we refuse to auto-fix
  };

  const { collectionsByName } = currentIndex;
  const desiredNames = new Set(desiredCollections.map((c) => c.name));

  for (const dcol of desiredCollections) {
    const current = collectionsByName.get(dcol.name);
    if (!current) {
      plan.createCollections.push({
        name: dcol.name,
        modes: dcol.modes,
        variables: dcol.variables,
      });
      // A brand-new collection needs a value set for every variable/mode.
      for (const dvar of dcol.variables) {
        for (const [mode, value] of Object.entries(dvar.valuesByMode)) {
          plan.setValues.push({
            collectionName: dcol.name,
            variableName: dvar.name,
            mode,
            value,
            type: dvar.type,
            existing: false,
          });
        }
      }
      continue;
    }

    for (const mode of dcol.modes) {
      if (!current.modesByName.has(mode)) {
        plan.createModes.push({ collectionName: dcol.name, modeName: mode });
      }
    }

    for (const dvar of dcol.variables) {
      const cvar = current.variablesByName.get(dvar.name);
      if (!cvar) {
        plan.createVariables.push({
          collectionName: dcol.name,
          variable: dvar,
        });
        for (const [mode, value] of Object.entries(dvar.valuesByMode)) {
          plan.setValues.push({
            collectionName: dcol.name,
            variableName: dvar.name,
            mode,
            value,
            type: dvar.type,
            existing: false,
          });
        }
        continue;
      }

      if (cvar.resolvedType !== dvar.type) {
        plan.warnings.push(
          `type mismatch for ${dcol.name} / ${dvar.name}: Figma=${cvar.resolvedType} manifest=${dvar.type}. ` +
            `Skipped (changing a variable's type needs delete+recreate, which this tool refuses to do). Fix in Figma manually if intended.`,
        );
        continue;
      }

      const changes = {};
      if (!scopesEqual(cvar.scopes, dvar.scopes)) changes.scopes = dvar.scopes;
      if (!codeSyntaxEqual(cvar.codeSyntax, dvar.codeSyntax))
        changes.codeSyntax = dvar.codeSyntax;
      if ((cvar.description || "") !== (dvar.description || ""))
        changes.description = dvar.description;
      if (Object.keys(changes).length > 0) {
        plan.updateVariables.push({
          collectionName: dcol.name,
          name: dvar.name,
          id: cvar.id,
          changes,
        });
      }

      for (const [mode, value] of Object.entries(dvar.valuesByMode)) {
        const modeId = current.modesByName.get(mode);
        const currentValue =
          modeId !== undefined ? cvar.valuesByMode[modeId] : undefined;
        if (!valuesEqual(dvar.type, currentValue, value)) {
          plan.setValues.push({
            collectionName: dcol.name,
            variableName: dvar.name,
            mode,
            value,
            type: dvar.type,
            existing: true,
          });
        }
      }
    }
  }

  // Report (never delete) anything in Figma missing from the manifest.
  for (const [colName, cur] of collectionsByName.entries()) {
    if (!desiredNames.has(colName)) {
      plan.extras.collections.push(colName);
      continue;
    }
    const dcol = desiredCollections.find((c) => c.name === colName);
    const desiredVarNames = new Set(dcol.variables.map((v) => v.name));
    for (const vName of cur.variablesByName.keys()) {
      if (!desiredVarNames.has(vName)) {
        plan.extras.variables.push(`${colName} / ${vName}`);
      }
    }
  }

  return plan;
}

export function planIsEmpty(plan) {
  return (
    plan.createCollections.length === 0 &&
    plan.createModes.length === 0 &&
    plan.createVariables.length === 0 &&
    plan.updateVariables.length === 0 &&
    plan.setValues.length === 0
  );
}

const slug = (s) => String(s).replace(/[^a-zA-Z0-9]+/g, "_");

/**
 * Build the POST /variables body from a plan using temp ids for created
 * objects. CREATE-OR-UPDATE ONLY — this function never emits a DELETE action.
 * `currentIndex` supplies real ids/modeIds for existing objects.
 */
export function buildPostPayload(plan, currentIndex) {
  const payload = {
    variableCollections: [],
    variableModes: [],
    variables: [],
    variableModeValues: [],
  };
  // temp-id registries so setValues can reference freshly-created objects
  const tmpModeId = new Map(); // `${col}\u0000${mode}` -> tmp/real modeId
  const tmpVarId = new Map(); // `${col}\u0000${var}` -> tmp/real variableId
  const tmpColId = new Map(); // col -> tmp/real collectionId

  const { collectionsByName } = currentIndex;
  const modeKey = (c, m) => `${c}\u0000${m}`;
  const varKey = (c, v) => `${c}\u0000${v}`;

  // Seed registries with existing real ids.
  for (const [colName, cur] of collectionsByName.entries()) {
    tmpColId.set(colName, cur.id);
    for (const [mName, mId] of cur.modesByName.entries())
      tmpModeId.set(modeKey(colName, mName), mId);
    for (const [vName, v] of cur.variablesByName.entries())
      tmpVarId.set(varKey(colName, vName), v.id);
  }

  // New collections (+ their initial/extra modes, variables, values).
  for (const col of plan.createCollections) {
    const colTmp = `tmpcol_${slug(col.name)}`;
    tmpColId.set(col.name, colTmp);
    const modes = col.modes.length > 0 ? col.modes : ["Value"];
    const initialModeTmp = `tmpmode_${slug(col.name)}_${slug(modes[0])}`;
    payload.variableCollections.push({
      action: "CREATE",
      id: colTmp,
      name: col.name,
      initialModeId: initialModeTmp,
    });
    // Rename the auto-created initial mode to our first mode.
    payload.variableModes.push({
      action: "UPDATE",
      id: initialModeTmp,
      name: modes[0],
      variableCollectionId: colTmp,
    });
    tmpModeId.set(modeKey(col.name, modes[0]), initialModeTmp);
    for (const m of modes.slice(1)) {
      const mTmp = `tmpmode_${slug(col.name)}_${slug(m)}`;
      payload.variableModes.push({
        action: "CREATE",
        id: mTmp,
        name: m,
        variableCollectionId: colTmp,
      });
      tmpModeId.set(modeKey(col.name, m), mTmp);
    }
    for (const v of col.variables) {
      const vTmp = `tmpvar_${slug(col.name)}_${slug(v.name)}`;
      tmpVarId.set(varKey(col.name, v.name), vTmp);
      payload.variables.push({
        action: "CREATE",
        id: vTmp,
        name: v.name,
        variableCollectionId: colTmp,
        resolvedType: v.type,
        scopes: v.scopes,
        codeSyntax: v.codeSyntax,
        ...(v.description ? { description: v.description } : {}),
      });
    }
  }

  // New modes on existing collections.
  for (const cm of plan.createModes) {
    const colId = tmpColId.get(cm.collectionName);
    const mTmp = `tmpmode_${slug(cm.collectionName)}_${slug(cm.modeName)}`;
    payload.variableModes.push({
      action: "CREATE",
      id: mTmp,
      name: cm.modeName,
      variableCollectionId: colId,
    });
    tmpModeId.set(modeKey(cm.collectionName, cm.modeName), mTmp);
  }

  // New variables on existing collections.
  for (const cv of plan.createVariables) {
    const colId = tmpColId.get(cv.collectionName);
    const vTmp = `tmpvar_${slug(cv.collectionName)}_${slug(cv.variable.name)}`;
    tmpVarId.set(varKey(cv.collectionName, cv.variable.name), vTmp);
    payload.variables.push({
      action: "CREATE",
      id: vTmp,
      name: cv.variable.name,
      variableCollectionId: colId,
      resolvedType: cv.variable.type,
      scopes: cv.variable.scopes,
      codeSyntax: cv.variable.codeSyntax,
      ...(cv.variable.description
        ? { description: cv.variable.description }
        : {}),
    });
  }

  // Metadata updates on existing variables.
  for (const uv of plan.updateVariables) {
    payload.variables.push({
      action: "UPDATE",
      id: uv.id,
      ...(uv.changes.scopes ? { scopes: uv.changes.scopes } : {}),
      ...(uv.changes.codeSyntax ? { codeSyntax: uv.changes.codeSyntax } : {}),
      ...(uv.changes.description !== undefined
        ? { description: uv.changes.description }
        : {}),
    });
  }

  // Values (references real or temp variable/mode ids).
  for (const sv of plan.setValues) {
    const variableId = tmpVarId.get(varKey(sv.collectionName, sv.variableName));
    const modeId = tmpModeId.get(modeKey(sv.collectionName, sv.mode));
    payload.variableModeValues.push({ variableId, modeId, value: sv.value });
  }

  return payload;
}

/** Defense in depth: throw if any action is DELETE. */
export function assertNoDeletes(payload) {
  for (const key of ["variableCollections", "variableModes", "variables"]) {
    for (const op of payload[key] || []) {
      if (op.action === "DELETE") {
        throw new Error(
          `refusing to send DELETE action in ${key} — this tool is create-or-update only`,
        );
      }
    }
  }
  return true;
}

// ---------------------------------------------------------------------------
// I/O
// ---------------------------------------------------------------------------

/** Wraps a Figma REST response, surfacing auth/scope problems explicitly. */
class FigmaError extends Error {
  constructor(message, { status, scope } = {}) {
    super(message);
    this.name = "FigmaError";
    this.status = status;
    this.scope = scope === true;
  }
}

async function figmaGetLocalVariables(fileKey, token) {
  const res = await fetch(
    `${FIGMA_API}/v1/files/${encodeURIComponent(fileKey)}/variables/local`,
    { headers: { "X-Figma-Token": token } },
  );
  const body = await res.json().catch(() => ({}));
  if (!res.ok) {
    const msg = body && body.message ? body.message : res.statusText;
    throw new FigmaError(`GET variables/local failed (${res.status}): ${msg}`, {
      status: res.status,
      scope: res.status === 403 || res.status === 401,
    });
  }
  return body.meta || {};
}

async function figmaPostVariables(fileKey, token, payload) {
  const res = await fetch(
    `${FIGMA_API}/v1/files/${encodeURIComponent(fileKey)}/variables`,
    {
      method: "POST",
      headers: {
        "X-Figma-Token": token,
        "Content-Type": "application/json",
      },
      body: JSON.stringify(payload),
    },
  );
  const body = await res.json().catch(() => ({}));
  if (!res.ok) {
    const msg = body && body.message ? body.message : res.statusText;
    throw new FigmaError(`POST variables failed (${res.status}): ${msg}`, {
      status: res.status,
      scope: res.status === 403 || res.status === 401,
    });
  }
  return body.meta || {};
}

// ---------------------------------------------------------------------------
// Reporting
// ---------------------------------------------------------------------------

function summarize(plan) {
  return {
    createCollections: plan.createCollections.length,
    createModes: plan.createModes.length,
    createVariables: plan.createVariables.length,
    updateVariables: plan.updateVariables.length,
    setValues: plan.setValues.length,
    extraCollections: plan.extras.collections.length,
    extraVariables: plan.extras.variables.length,
    warnings: plan.warnings.length,
  };
}

function renderReport(plan, { fileKey }) {
  const s = summarize(plan);
  const lines = [];
  lines.push(`Figma variables sync — dry-run diff (file ${fileKey})`);
  lines.push("");
  lines.push(`  collections to create : ${s.createCollections}`);
  lines.push(`  modes to create       : ${s.createModes}`);
  lines.push(`  variables to create   : ${s.createVariables}`);
  lines.push(`  variables to update   : ${s.updateVariables}`);
  lines.push(`  values to set         : ${s.setValues}`);
  lines.push(
    `  extra in Figma (kept) : ${s.extraCollections} collection(s), ${s.extraVariables} variable(s)`,
  );
  lines.push("");

  const list = (title, items) => {
    if (items.length === 0) return;
    lines.push(title);
    for (const it of items) lines.push(`  + ${it}`);
    lines.push("");
  };
  list(
    "CREATE collections:",
    plan.createCollections.map(
      (c) =>
        `${c.name} (${c.variables.length} vars, modes: ${c.modes.join(", ")})`,
    ),
  );
  list(
    "CREATE modes:",
    plan.createModes.map((m) => `${m.collectionName} / ${m.modeName}`),
  );
  list(
    "CREATE variables:",
    plan.createVariables.map(
      (v) => `${v.collectionName} / ${v.variable.name} (${v.variable.type})`,
    ),
  );
  list(
    "UPDATE variables (metadata):",
    plan.updateVariables.map(
      (v) =>
        `${v.collectionName} / ${v.name} [${Object.keys(v.changes).join(", ")}]`,
    ),
  );
  list(
    "SET values:",
    plan.setValues.map(
      (v) =>
        `${v.collectionName} / ${v.variableName} @ ${v.mode}${v.existing ? "" : " (new var)"}`,
    ),
  );

  if (plan.extras.collections.length || plan.extras.variables.length) {
    lines.push(
      "EXTRA in Figma, NOT in manifest — LEFT UNTOUCHED (never deleted):",
    );
    for (const c of plan.extras.collections) lines.push(`  · collection ${c}`);
    for (const v of plan.extras.variables) lines.push(`  · variable ${v}`);
    lines.push("");
  }
  if (plan.warnings.length) {
    lines.push("WARNINGS:");
    for (const w of plan.warnings) lines.push(`  ! ${w}`);
    lines.push("");
  }
  if (planIsEmpty(plan)) {
    lines.push(
      "Figma is already in sync with the manifest. No changes needed.",
    );
  }
  return lines.join("\n");
}

function writeStepSummary(text) {
  const path = process.env.GITHUB_STEP_SUMMARY;
  if (!path) return;
  try {
    appendFileSync(path, "```\n" + text + "\n```\n");
  } catch {
    /* best effort — the summary is a nice-to-have, never fatal */
  }
}

// ---------------------------------------------------------------------------
// CLI
// ---------------------------------------------------------------------------

function parseArgs(argv) {
  const args = {
    apply: false,
    dryRun: true,
    json: false,
    fileKey: null,
    manifest: null,
    current: null,
  };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--apply") {
      args.apply = true;
      args.dryRun = false;
    } else if (a === "--dry-run" || a === "--report") {
      args.dryRun = true;
      args.apply = false;
    } else if (a === "--json") {
      args.json = true;
    } else if (a === "--file-key") {
      args.fileKey = argv[++i];
    } else if (a === "--manifest") {
      args.manifest = argv[++i];
    } else if (a === "--current") {
      args.current = argv[++i];
    }
  }
  return args;
}

function loadManifest(manifestPath) {
  const root = join(dirname(fileURLToPath(import.meta.url)), "..");
  const p = manifestPath
    ? resolve(manifestPath)
    : join(root, "figma-tokens.json");
  return JSON.parse(readFileSync(p, "utf8"));
}

async function main(rawArgv) {
  const args = parseArgs(rawArgv.slice(2));
  const manifest = loadManifest(args.manifest);
  const fileKey = args.fileKey || manifest.fileKeyHint || DEFAULT_FILE_KEY;
  const token = process.env.FIGMA_ACCESS_TOKEN || "";
  const desired = buildDesiredCollections(manifest);

  if (Array.isArray(manifest.effectStyles) && manifest.effectStyles.length) {
    console.log(
      `Note: ${manifest.effectStyles.length} effect style(s) in the manifest are not synced — ` +
        `the Figma REST API cannot create/update styles (plugin/UI only). Their bound colors ARE synced as variables.`,
    );
  }

  // Obtain current Figma state (network, or --current file for offline tests).
  let meta;
  if (args.current) {
    const parsed = JSON.parse(readFileSync(resolve(args.current), "utf8"));
    meta = parsed.meta || parsed;
  } else {
    if (!token) {
      const msg =
        "FIGMA_ACCESS_TOKEN is not set. Cannot read current Figma variables to diff. " +
        "Add a Figma PAT with the 'file_variables:read' scope (Enterprise) to enable the sync report.";
      console.log(`::warning title=Figma variables sync skipped::${msg}`);
      console.log("\nDesired manifest summary (no diff — token missing):");
      for (const c of desired)
        console.log(`  ${c.name}: ${c.variables.length} variables`);
      writeStepSummary(msg);
      return 0; // report-only job stays green; nothing was written
    }
    try {
      meta = await figmaGetLocalVariables(fileKey, token);
    } catch (err) {
      if (err instanceof FigmaError && err.scope) {
        const msg =
          `Figma variables read failed (${err.status}). The FIGMA_ACCESS_TOKEN PAT likely lacks the ` +
          `'file_variables:read' scope, or the account/plan is not Enterprise. Figma said: ${err.message}. ` +
          `Grant Variables read+write (Enterprise) to enable this sync. Docs: https://developers.figma.com/docs/rest-api/variables/`;
        console.log(`::warning title=Figma PAT scope::${msg}`);
        writeStepSummary(msg);
        return 0; // graceful: don't turn main red on an expected-unknown scope
      }
      throw err; // unexpected — fail loudly
    }
  }

  const currentIndex = indexCurrent(meta);
  const plan = diff(desired, currentIndex);
  const report = renderReport(plan, { fileKey });

  if (args.json) {
    console.log(JSON.stringify({ summary: summarize(plan), plan }, null, 2));
  } else {
    console.log(report);
  }
  writeStepSummary(report);

  // Build + validate the payload regardless of mode (also serves as a smoke
  // check that the plan is serialisable and delete-free).
  const payload = buildPostPayload(plan, currentIndex);
  assertNoDeletes(payload);

  if (args.dryRun || !args.apply) {
    if (!planIsEmpty(plan)) {
      console.log(
        "\nDry-run only — no changes were written to Figma. Re-run with --apply (and FIGMA_SYNC_ALLOW_APPLY=1) to apply.",
      );
    }
    return 0;
  }

  // ----- apply path (double-gated) -----
  console.log(
    "\n--- POST payload that would be sent (create-or-update only) ---",
  );
  console.log(JSON.stringify(payload, null, 2));
  if (process.env.FIGMA_SYNC_ALLOW_APPLY !== "1") {
    console.log(
      "\nRefusing to apply: set FIGMA_SYNC_ALLOW_APPLY=1 to confirm the (create-or-update only) write above. Nothing was sent.",
    );
    return 0;
  }
  if (planIsEmpty(plan)) {
    console.log("\nNothing to apply — Figma already matches the manifest.");
    return 0;
  }
  const result = await figmaPostVariables(fileKey, token, payload);
  console.log(
    `\nApplied. Figma returned ${Object.keys(result.tempIdToRealId || {}).length} new id mapping(s).`,
  );
  return 0;
}

// Only run main when executed directly (not when imported by tests).
const invokedDirectly =
  process.argv[1] &&
  resolve(process.argv[1]) === fileURLToPath(import.meta.url);
if (invokedDirectly) {
  main(process.argv)
    .then((code) => process.exit(code || 0))
    .catch((err) => {
      console.error(
        `::error title=Figma variables sync failed::${err.message}`,
      );
      process.exit(1);
    });
}
